package middleware

import (
	"context"
	"fmt"
	"net/http"
	"strings"
)

type contextKey string

const userContextKey contextKey = "auth_user"

type User struct {
	ID    string
	Email string
	Role  string
}

// GetUser extracts the authenticated user from the request context.
func GetUser(ctx context.Context) *User {
	user, _ := ctx.Value(userContextKey).(*User)
	return user
}

func AuthMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		token := r.Header.Get("Authorization")
		if token == "" {
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		token = strings.TrimPrefix(token, "Bearer ")
		user, err := validateToken(token)
		if err != nil {
			http.Error(w, "Invalid token", http.StatusUnauthorized)
			return
		}

		ctx := context.WithValue(r.Context(), userContextKey, user)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

func validateToken(token string) (*User, error) {
	parts := strings.Split(token, ":")
	if len(parts) != 3 {
		return nil, fmt.Errorf("invalid token format")
	}
	return &User{ID: parts[0], Email: parts[1], Role: parts[2]}, nil
}

func AdminHandler(w http.ResponseWriter, r *http.Request) {
	user := middleware.GetUser(r.Context())
	if user == nil || user.Role != "admin" {
		http.Error(w, "Forbidden", http.StatusForbidden)
		return
	}
	json.NewEncoder(w).Encode(map[string]string{"admin": user.Email})
}

func TestAuthMiddleware_ValidToken(t *testing.T) {
	var capturedUser *User
	next := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		capturedUser = GetUser(r.Context())
	})

	handler := AuthMiddleware(next)
	req := httptest.NewRequest("GET", "/", nil)
	req.Header.Set("Authorization", "Bearer id1:user@test.com:admin")
	rr := httptest.NewRecorder()
	handler.ServeHTTP(rr, req)

	if capturedUser == nil {
		t.Fatal("expected user in context")
	}
	if capturedUser.ID != "id1" {
		t.Errorf("expected ID 'id1', got '%s'", capturedUser.ID)
	}
	if capturedUser.Role != "admin" {
		t.Errorf("expected Role 'admin', got '%s'", capturedUser.Role)
	}
}
